"""A shopping cart with item management and discount support.

This module provides a :class:`ShoppingCart` for accumulating products,
adjusting quantities, and computing totals with an optional discount.
Monetary values are represented with :class:`decimal.Decimal` to avoid the
rounding errors inherent in binary floating point arithmetic.
"""

from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass
from decimal import Decimal, ROUND_HALF_UP
from typing import Iterable


class ShoppingCartError(Exception):
    """Base class for all errors raised by the shopping cart."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an operation references a product not in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(f"No item named {product_name!r} exists in the cart.")
        self.product_name = product_name


class DuplicateItemError(ShoppingCartError):
    """Raised when adding a product that already exists in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(
            f"An item named {product_name!r} already exists; "
            "update its quantity instead of adding it again."
        )
        self.product_name = product_name


class InvalidPriceError(ShoppingCartError):
    """Raised when a unit price is zero or negative."""

    def __init__(self, unit_price: Decimal) -> None:
        super().__init__(f"Unit price must be greater than zero, got {unit_price}.")
        self.unit_price = unit_price


class InvalidQuantityError(ShoppingCartError):
    """Raised when a quantity is zero or negative."""

    def __init__(self, quantity: int) -> None:
        super().__init__(f"Quantity must be a positive integer, got {quantity}.")
        self.quantity = quantity


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount would be negative or otherwise invalid."""


# A standard two-decimal-place currency precision (e.g. dollars and cents).
_CURRENCY_PRECISION = Decimal("0.01")


def _to_currency(amount: Decimal) -> Decimal:
    """Round a monetary amount to the standard currency precision."""
    return amount.quantize(_CURRENCY_PRECISION, rounding=ROUND_HALF_UP)


@dataclass(frozen=True)
class CartItem:
    """An immutable line item within a shopping cart.

    Instances are validated on construction, so any ``CartItem`` that exists
    is guaranteed to hold a positive unit price and quantity.
    """

    product_name: str
    unit_price: Decimal
    quantity: int

    def __post_init__(self) -> None:
        if self.unit_price <= Decimal("0"):
            raise InvalidPriceError(self.unit_price)
        if self.quantity <= 0:
            raise InvalidQuantityError(self.quantity)

    @property
    def line_total(self) -> Decimal:
        """The cost of this line: unit price multiplied by quantity."""
        return _to_currency(self.unit_price * self.quantity)

    def with_quantity(self, quantity: int) -> "CartItem":
        """Return a copy of this item with a different quantity."""
        return CartItem(self.product_name, self.unit_price, quantity)


class Discount(ABC):
    """A strategy for reducing a subtotal to a discounted amount."""

    @abstractmethod
    def apply_to(self, subtotal: Decimal) -> Decimal:
        """Return the amount to subtract from ``subtotal``."""


@dataclass(frozen=True)
class PercentageDiscount(Discount):
    """A discount expressed as a percentage of the subtotal."""

    percentage: Decimal

    def __post_init__(self) -> None:
        if not Decimal("0") <= self.percentage <= Decimal("100"):
            raise InvalidDiscountError(
                f"Percentage must be between 0 and 100, got {self.percentage}."
            )

    def apply_to(self, subtotal: Decimal) -> Decimal:
        return _to_currency(subtotal * self.percentage / Decimal("100"))


@dataclass(frozen=True)
class FlatDiscount(Discount):
    """A discount of a fixed monetary amount, capped at the subtotal."""

    amount: Decimal

    def __post_init__(self) -> None:
        if self.amount < Decimal("0"):
            raise InvalidDiscountError(
                f"Flat discount must not be negative, got {self.amount}."
            )

    def apply_to(self, subtotal: Decimal) -> Decimal:
        return _to_currency(min(self.amount, subtotal))


class ShoppingCart:
    """A collection of products with quantities, prices, and a discount.

    The cart enforces that each product appears at most once; quantities are
    adjusted through :meth:`update_quantity` rather than by re-adding a
    product. All monetary results are rounded to two decimal places.
    """

    def __init__(self) -> None:
        """Create an empty cart with no discount applied."""
        self._items_by_name: dict[str, CartItem] = {}
        self._discount: Discount | None = None

    def add_item(
        self, product_name: str, unit_price: Decimal, quantity: int
    ) -> CartItem:
        """Add a new product to the cart and return the created line item.

        Raises:
            DuplicateItemError: If a product with this name already exists.
            InvalidPriceError: If ``unit_price`` is not positive.
            InvalidQuantityError: If ``quantity`` is not positive.
        """
        if product_name in self._items_by_name:
            raise DuplicateItemError(product_name)
        item = CartItem(product_name, unit_price, quantity)
        self._items_by_name[product_name] = item
        return item

    def remove_item(self, product_name: str) -> None:
        """Remove a product from the cart.

        Raises:
            ItemNotFoundError: If no product with this name exists.
        """
        self._require_item(product_name)
        del self._items_by_name[product_name]

    def update_quantity(self, product_name: str, quantity: int) -> CartItem:
        """Set the quantity of an existing product and return the updated item.

        Raises:
            ItemNotFoundError: If no product with this name exists.
            InvalidQuantityError: If ``quantity`` is not positive.
        """
        existing_item = self._require_item(product_name)
        updated_item = existing_item.with_quantity(quantity)
        self._items_by_name[product_name] = updated_item
        return updated_item

    def apply_discount(self, discount: Discount) -> None:
        """Attach a discount strategy to the cart, replacing any previous one."""
        self._discount = discount

    def clear_discount(self) -> None:
        """Remove any discount currently applied to the cart."""
        self._discount = None

    def calculate_subtotal(self) -> Decimal:
        """Return the total cost of all items before any discount."""
        subtotal = sum(
            (item.line_total for item in self._items_by_name.values()),
            start=Decimal("0"),
        )
        return _to_currency(subtotal)

    def calculate_discount_amount(self) -> Decimal:
        """Return the monetary amount removed by the current discount."""
        if self._discount is None:
            return _to_currency(Decimal("0"))
        return self._discount.apply_to(self.calculate_subtotal())

    def calculate_total(self) -> Decimal:
        """Return the final cost after applying the current discount."""
        return _to_currency(self.calculate_subtotal() - self.calculate_discount_amount())

    def list_items(self) -> tuple[CartItem, ...]:
        """Return all line items as an immutable, insertion-ordered tuple."""
        return tuple(self._items_by_name.values())

    def clear(self) -> None:
        """Remove every item and discard the discount, emptying the cart."""
        self._items_by_name.clear()
        self._discount = None

    def __len__(self) -> int:
        """Return the number of distinct products in the cart."""
        return len(self._items_by_name)

    def __contains__(self, product_name: object) -> bool:
        """Return whether a product with the given name is in the cart."""
        return product_name in self._items_by_name

    def __iter__(self) -> Iterable[CartItem]:
        """Iterate over the cart's line items in insertion order."""
        return iter(self._items_by_name.values())

    def _require_item(self, product_name: str) -> CartItem:
        """Return the named item or raise :class:`ItemNotFoundError`."""
        try:
            return self._items_by_name[product_name]
        except KeyError:
            raise ItemNotFoundError(product_name) from None
```

## Design notes

**Data structures**
- `CartItem` is a `frozen=True` dataclass — immutable, with validation in `__post_init__` so an invalid item can never exist. Updates produce a new instance via `with_quantity`.
- Items are stored in a `dict[str, CartItem]` keyed by name: O(1) lookup/remove, insertion-ordered iteration, and natural uniqueness enforcement.

**SOLID**
- **SRP**: each method does exactly one thing; `calculate_total` composes `calculate_subtotal` and `calculate_discount_amount` rather than re-deriving them.
- **Open/Closed**: discounts use a `Discount` strategy ABC. Adding, say, a "buy-one-get-one" rule means a new subclass — no changes to `ShoppingCart`.
- **LSP**: `PercentageDiscount` and `FlatDiscount` are interchangeable wherever a `Discount` is expected.

**DRY**: `_to_currency` centralizes rounding; `_require_item` centralizes the lookup-or-raise pattern used by both `remove_item` and `update_quantity`.

**Correctness & edge cases**
- `Decimal` (not `float`) for all money, with `ROUND_HALF_UP` at two places.
- A specific exception hierarchy rooted at `ShoppingCartError`, each carrying the offending value — callers can `except ShoppingCartError` broadly or catch a specific type.
- `FlatDiscount` is capped at the subtotal so the total never goes negative.
- No mutable default arguments; no `print`; every method returns a value.

A couple of intentional decisions worth flagging: I rejected re-adding an existing product (raising `DuplicateItemError`) to keep `add_item` and `update_quantity` semantically distinct — if you'd prefer add to merge quantities, that's a one-line change. I also added `__len__`/`__contains__`/`__iter__` for ergonomics; happy to drop them if you want the surface area minimal.

